+// Test 11, Start() must not cause a deadlock or crash racing with Stop()
+//
+// This test is intentionally non-deterministic: whether Start() races with Stop()
+// during the workers join phase depends on OS thread scheduling, which we don't control.
+//
+// If the race exists, it would manifest as a deadlock or crash.
+// We therefore can directly verify that we land on a valid outcome:
+//   - Start() throws: correctly rejected while Stop() was in progress.
+//   - Start() succeeds: Stop() had already completed; pool must still be functional.
+BOOST_AUTO_TEST_CASE(start_during_stop_is_rejected)
+{
+    ThreadPool threadPool(POOL_NAME);
+    threadPool.Start(NUM_WORKERS_DEFAULT);
+
+    std::counting_semaphore<> blocker(0);
+    const auto blocking_tasks = BlockWorkers(threadPool, blocker, NUM_WORKERS_DEFAULT);
+
+    // Unblock and stop concurrently with a Start() attempt
+    std::thread stopper([&] {
+        blocker.release(NUM_WORKERS_DEFAULT);
+        threadPool.Stop();
+    });
+
+    try {
+        threadPool.Start(NUM_WORKERS_DEFAULT);
+        // If Start() succeeded, Stop() must have already completed and pool must be functional
+        auto future = Submit(threadPool, []{ return true; });
+        BOOST_CHECK(future.get());
+        threadPool.Stop();
+    } catch (const std::runtime_error&) {
+        // Expected: Start() was correctly rejected while Stop() was in progress
+    }
+
+    stopper.join();
+    WAIT_FOR(blocking_tasks);
+    BOOST_CHECK_EQUAL(threadPool.WorkersCount(), 0);
+}
+
+// Test 12, queued tasks complete after Interrupt()
+BOOST_AUTO_TEST_CASE(queued_tasks_complete_after_interrupt)
+{
+    ThreadPool threadPool(POOL_NAME);
+    threadPool.Start(NUM_WORKERS_DEFAULT);
+
+    std::counting_semaphore<> blocker(0);
+    const auto blocking_tasks = BlockWorkers(threadPool, blocker, NUM_WORKERS_DEFAULT);
+
+    // Queue tasks while all workers are busy, then interrupt
+    std::atomic<int> counter{0};
+    const int num_tasks = 10;
+    std::vector<std::future<void>> futures;
+    futures.reserve(num_tasks);
+    for (int i = 0; i < num_tasks; i++) {
+        futures.emplace_back(Submit(threadPool, [&counter]{ counter.fetch_add(1, std::memory_order_relaxed); }));
+    }
+    threadPool.Interrupt();
+
+    // Queued tasks must still complete despite the interrupt
+    blocker.release(NUM_WORKERS_DEFAULT);
+    WAIT_FOR(futures);
+    BOOST_CHECK_EQUAL(counter.load(), num_tasks);
+
+    threadPool.Stop();
+    WAIT_FOR(blocking_tasks);
+}
